  /** Small deterministic-enough delay for the retry-backoff loop. */
  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private toEcaRuleFields(
    event: AutomationEvent,
  ): Record<string, string | number> {
    const fields: Record<string, string | number> = { kind: event.kind };
    if (event.text !== undefined) {
      fields.text = event.text;
    }
    if (event.chatId !== undefined) {
      fields.chatId = event.chatId;
    }
    if (event.isNewUser !== undefined) {
      fields.isNewUser = event.isNewUser ? 1 : 0;
    }
    return fields;
  }

  /**
   * Builds the trigger graph for rule-loop-detector.ts. Conservative model:
   * only a "message" rule whose action is "reply" can plausibly re-trigger
   * another "message" rule in the same chat (the bot's own reply is itself a
   * new message event). Every other action kind (delete/quarantine/
   * notify_staff/log/mute/webhook/assign_mission) does not re-emit an
   * AutomationEvent this engine listens for, so it contributes no edges.
   */
  private buildEcaRuleEdges(rules: readonly EcaRuleRecord[]): RuleEdge[] {
    const messageRules = rules.filter((r) => r.event === "message");
    const edges: RuleEdge[] = [];
    for (const source of rules) {
      if (source.event !== "message" || source.action.kind !== "reply") {
        continue;
      }
      for (const target of messageRules) {
        edges.push({ from: source.id, to: target.id });
      }
    }
    return edges;
  }

  /**
   * Rejects a candidate rule that would create an infinite trigger loop
   * BEFORE it is persisted (rule-loop-detector.ts: hasRuleLoop). This is the
   * hook point for whichever future admin command / Mini App endpoint lets
   * an owner author EcaRule rows — none exists yet, so nothing calls this
   * today, but createEcaRuleGuarded below is ready to be wired to one.
   */
  private async assertNoEcaRuleLoop(
    tenantId: string,
    chatId: string | null,
    candidate: EcaRuleRecord,
  ): Promise<void> {
    const existing = await this.ecaRuleRepository.list(
      tenantId,
      chatId ?? undefined,
    );
    const rules = [...existing.filter((r) => r.id !== candidate.id), candidate];
    if (hasRuleLoop(this.buildEcaRuleEdges(rules))) {
      throw new Error(
        "Esta regla crearía un bucle de disparo infinito con otra regla ECA " +
          "existente (p. ej. una regla \"reply\" cuyo mensaje volvería a activar " +
          "otra regla \"message\"); ajusta el evento, las condiciones o la acción.",
      );
    }
  }

  /** Loop-guarded create — the entry point any future rule-authoring UI/command should call instead of ecaRuleRepository.create directly. */
  async createEcaRuleGuarded(
    tenantId: string,
    chatId: string | null,
    event: string,
    conditions: readonly EcaRuleConditionRecord[],
    action: AutomationAction,
    options?: { cooldownMs?: number | null; expiresAtMs?: number | null },
  ): Promise<EcaRuleRecord> {
    const candidate: EcaRuleRecord = {
      id: "__eca_candidate__",
      tenantId,
      chatId,
      event,
      conditions,
      action,
      enabled: true,
      cooldownMs: options?.cooldownMs ?? null,
      expiresAtMs: options?.expiresAtMs ?? null,
      lastFiredMs: null,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await this.assertNoEcaRuleLoop(tenantId, chatId, candidate);
    return this.ecaRuleRepository.create(
      tenantId,
      chatId,
      event,
      conditions,
      action,
      options,
    );
  }

  /**
   * Runs a failed automation action through retry-backoff.ts
   * (computeBackoffMs/shouldRetry) instead of dropping it silently. Once
   * retries are exhausted, hands off to the JobOutbox repository so the
   * worker can keep retrying on its own schedule rather than losing the
   * action — this is the same gap flagged by the literal TODO in
   * apps/api/src/guardian/guardian-verify.service.ts ("route through
   * JobOutbox for retry-with-backoff"), reused here for ECA actions too.
   */
  private async executeEcaActionWithRetry(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
    action: AutomationAction,
    ruleId: string,
  ): Promise<void> {
    const maxAttempts = 3;
    for (let attempt = 0; ; attempt += 1) {
      try {
        await this.executeAutomationAction(context, update, action);
        return;
      } catch (err) {
        if (!shouldRetry(attempt, maxAttempts)) {
          try {
            await this.jobOutboxRepository.enqueue(
              context.tenantId,
              "eca.action.retry",
              {
                ruleId,
                chatId: context.chatId,
                action,
                lastError: err instanceof Error ? err.message : String(err),
              },
            );
          } catch {
            // Even the outbox enqueue is best-effort: never let a bookkeeping
            // failure surface to the original update handling.
          }
          return;
        }
        await this.delay(computeBackoffMs(attempt, 500, 15_000));
      }
    }
  }

  /**
   * D9-parallel: evaluates every enabled EcaRule scoped to this chat (or
   * tenant-wide) against the event using the PURE rule-engine.ts
   * (evaluateRules), then executes the SAME action vocabulary as the
   * existing simple automations via executeAutomationAction (through the
   * retry wrapper above) — reuses the executor, does not duplicate it. This
   * is a NEW, PARALLEL surface: matchAndRunAutomations/matchAutomation
   * (OwnerNetworkAutomation) is untouched and keeps running alongside.
   *
   * Rules are grouped into evaluateRules() batches by their persisted
   * lastFiredMs value, because RuleContext carries a single lastFiredMs for
   * the whole batch but each EcaRule has its OWN independent cooldown clock
   * — grouping by that value lets rules sharing the same last-fired instant
   * (most commonly "never fired", i.e. null) be evaluated together in one
   * evaluateRules call, while a rule with a distinct lastFiredMs gets its
   * own single-rule batch, without ever touching evaluateRule's cooldown
   * logic by hand.
   */
  private async matchAndRunEcaRules(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
    event: AutomationEvent,
  ): Promise<void> {
    if (!context.chatId) {
      return;
    }
    try {
      const rules = await this.ecaRuleRepository.listActiveForEvent(
        context.tenantId,
        context.chatId,
        event.kind,
      );
      if (rules.length === 0) {
        return;
      }
      const nowMs = Date.now();
      const byId = new Map(rules.map((r) => [r.id, r] as const));
      const buckets = new Map<number | undefined, EcaRule[]>();
      for (const record of rules) {
        const pureRule: EcaRule = {
          id: record.id,
          event: record.event,
          conditions: record.conditions,
          action: record.id,
          ...(record.cooldownMs !== null
            ? { cooldownMs: record.cooldownMs }
            : {}),
          ...(record.expiresAtMs !== null
            ? { expiresAtMs: record.expiresAtMs }
            : {}),
        };
        const bucketKey = record.lastFiredMs ?? undefined;
        const bucket = buckets.get(bucketKey) ?? [];
        bucket.push(pureRule);
        buckets.set(bucketKey, bucket);
      }

      const fields = this.toEcaRuleFields(event);
      for (const [lastFiredMs, bucketRules] of buckets) {
        const ruleCtx: RuleContext = {
          event: event.kind,
          fields,
          nowMs,
          ...(lastFiredMs !== undefined ? { lastFiredMs } : {}),
        };
        const { fired } = evaluateRules(bucketRules, ruleCtx);
        for (const firedRule of fired) {
          const record = byId.get(firedRule.id);
          if (!record) {
            continue;
          }
          await this.ecaRuleRepository.recordFired(record.id, nowMs);
          await this.executeEcaActionWithRetry(
            context,
            update,
            record.action,
            record.id,
          );
        }
      }
    } catch {
      // ECA rules are best-effort, never a gate on the original update —
      // same guarantee as matchAndRunAutomations right above it.
    }
  }

  private async runEcaRulesForMessage(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<void> {
    if (
      update.kind !== "message" ||
      !context.chatId ||
      isServiceMessage(update.raw)
    ) {
      return;
    }
    await this.matchAndRunEcaRules(context, update, {
      kind: "message",
      ...(update.messageText ? { text: update.messageText } : {}),
      chatId: context.chatId,
    });
  }

  private async runEcaRulesForNewMembers(
    context: FoundationContext,
    update: TelegramUpdateEnvelope,
  ): Promise<void> {
    if (!context.chatId || update.newChatMemberIds.length === 0) {
      return;
    }
    await this.matchAndRunEcaRules(context, update, {
      kind: "new_member",
      chatId: context.chatId,
    });
  }

